head.b:skin:
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        :root {
            --primary: #22c55e;
            --primary-dark: #16a34a;
            --secondary: #8b5cf6;
            --accent: #d97706;
            --background: #f8fafc;
            --foreground: #0f172a;
            --glass-bg: rgba(255, 255, 255, 0.6);
            --glass-border: rgba(255, 255, 255, 0.4);
        }

        :root.dark {
            --background: #0a0e12;
            --foreground: #f1f5f9;
            --glass-bg: rgba(255, 255, 255, 0.03);
            --glass-border: rgba(255, 255, 255, 0.08);
        }

        html[dir="rtl"] {
            direction: rtl;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', 'Oxygen', 'Ubuntu', 'Cantarell', sans-serif;
            background: var(--background);
            color: var(--foreground);
            line-height: 1.6;
            overflow-x: hidden;
            transition: background-color 0.3s ease, color 0.3s ease;
        }

        .glass {
            background: var(--glass-bg);
            backdrop-filter: blur(10px);
            -webkit-backdrop-filter: blur(10px);
            border: 1px solid var(--glass-border);
            box-shadow: 0 4px 30px rgba(0, 0, 0, 0.05);
        }

        :root.dark .glass {
            box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);
        }

        .glass-card {
            background: rgba(255, 255, 255, 0.7);
            backdrop-filter: blur(12px);
            -webkit-backdrop-filter: blur(12px);
            border: 1px solid rgba(255, 255, 255, 0.4);
            box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.1);
        }

        :root.dark .glass-card {
            background: rgba(30, 41, 59, 0.4);
            border: 1px solid rgba(255, 255, 255, 0.08);
            box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.3);
        }

        nav {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            z-index: 50;
            transition: all 0.3s ease;
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 1.25rem 1.5rem;
            border-bottom: 1px solid transparent;
            background: var(--background);
        }

        nav.scrolled {
            background: rgba(0, 0, 0, 0.1);
            backdrop-filter: blur(12px);
            border-bottom-color: rgba(255, 255, 255, 0.1);
            padding: 0.75rem 1.5rem;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
        }

        .nav-brand {
            font-size: 1.5rem;
            font-weight: 700;
            background: linear-gradient(to right, var(--primary), var(--accent));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        .nav-links {
            display: none;
            gap: 1.5rem;
            font-size: 0.875rem;
            font-weight: 500;
            list-style: none;
        }

        .nav-links a {
            color: inherit;
            text-decoration: none;
            transition: color 0.3s ease;
        }

        .nav-links a:hover {
            color: var(--primary);
        }

        @media (min-width: 1024px) {
            .nav-links {
                display: flex;
            }
        }

        .nav-controls {
            display: flex;
            gap: 1rem;
            align-items: center;
        }

        .nav-controls-group {
            display: none;
            gap: 0.75rem;
            background: rgba(0, 0, 0, 0.1);
            padding: 0.5rem 1rem;
            border-radius: 9999px;
            border: 1px rgba(0, 0, 0, 0.05) solid;
            align-items: center;
        }

        @media (min-width: 768px) {
            .nav-controls-group {
                display: flex;
            }
        }

        .nav-controls button {
            background: none;
            border: none;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            color: inherit;
            transition: color 0.3s ease;
            padding: 0.25rem;
        }

        .nav-controls button:hover {
            color: var(--primary);
        }

        .divider {
            width: 1px;
            height: 1rem;
            background: rgba(148, 163, 184, 0.3);
        }

        .nav-shop {
            background: var(--primary);
            color: white;
            padding: 0.5rem 1.25rem;
            border: none;
            border-radius: 9999px;
            font-weight: 600;
            cursor: pointer;
            font-size: 0.875rem;
            transition: background 0.3s ease;
            text-decoration: none;
            display: inline-block;
        }

        .nav-shop:hover {
            background: var(--primary-dark);
        }

        main {
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            position: relative;
            width: 100%;
            overflow: hidden;
            padding-top: 80px;
        }

        .bg-decorator {
            position: absolute;
            border-radius: 50%;
            filter: blur(120px);
            pointer-events: none;
        }

        .bg-decorator-1 {
            top: -10%;
            left: -10%;
            width: 40%;
            height: 40%;
            background: rgba(34, 197, 94, 0.2);
        }

        .bg-decorator-2 {
            bottom: -10%;
            right: -10%;
            width: 40%;
            height: 40%;
            background: rgba(216, 180, 254, 0.2);
        }

        :root.dark .bg-decorator-1 {
            background: rgba(34, 197, 94, 0.1);
        }

        :root.dark .bg-decorator-2 {
            background: rgba(216, 180, 254, 0.1);
        }

        #home {
            display: grid;
            grid-template-columns: 1fr;
            gap: 3rem;
            align-items: center;
            padding: 2rem 1.5rem;
            max-width: 80rem;
            margin: 0 auto;
            position: relative;
            z-index: 10;
            min-height: 90vh;
        }

        @media (min-width: 1024px) {
            #home {
                grid-template-columns: 1fr 1fr;
                text-align: left;
                padding: 8rem 1.5rem 5rem;
            }
        }

        .hero-content {
            display: flex;
            flex-direction: column;
            gap: 1.5rem;
            text-align: center;
        }

        @media (min-width: 1024px) {
            .hero-content {
                text-align: left;
            }
        }

        .hero-badge {
            display: inline-block;
            padding: 0.375rem 1rem;
            border-radius: 9999px;
            border: 1px solid rgba(34, 197, 94, 0.3);
            color: var(--primary);
            font-size: 0.875rem;
            font-weight: 600;
            background: var(--glass-bg);
            backdrop-filter: blur(10px);
            width: fit-content;
            margin: 0 auto;
        }

        @media (min-width: 1024px) {
            .hero-badge {
                margin: 0;
            }
        }

        .hero-title {
            font-size: 3rem;
            font-weight: 800;
            line-height: 1.2;
            letter-spacing: -0.02em;
        }

        @media (min-width: 768px) {
            .hero-title {
                font-size: 4.5rem;
            }
        }

        .hero-title span {
            display: block;
            background: linear-gradient(to right, var(--primary), var(--accent));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        .hero-desc {
            font-size: 1.125rem;
            color: #64748b;
            max-width: 40rem;
            line-height: 1.75;
        }

        :root.dark .hero-desc {
            color: #cbd5e1;
        }

        .hero-buttons {
            display: flex;
            flex-direction: column;
            gap: 1rem;
            margin-top: 1rem;
        }

        @media (min-width: 640px) {
            .hero-buttons {
                flex-direction: row;
            }
        }

        @media (min-width: 1024px) {
            .hero-buttons {
                justify-content: flex-start;
            }
        }

        .btn {
            padding: 1rem 2rem;
            border-radius: 9999px;
            font-weight: 700;
            font-size: 1.125rem;
            text-decoration: none;
            border: none;
            cursor: pointer;
            display: inline-flex;
            align-items: center;
            justify-content: center;
            gap: 0.5rem;
            transition: all 0.3s ease;
            text-align: center;
        }

        .btn-primary {
            background: var(--primary);
            color: white;
            box-shadow: 0 0 20px rgba(34, 197, 94, 0.5);
        }

        .btn-primary:hover {
            transform: scale(1.05);
            box-shadow: 0 0 30px rgba(34, 197, 94, 0.7);
        }

        .btn-primary:active {
            transform: scale(0.95);
        }

        .btn-secondary {
            background: var(--glass-bg);
            backdrop-filter: blur(10px);
            border: 1px solid rgba(0, 0, 0, 0.1);
            color: #1f2937;
        }

        :root.dark .btn-secondary {
            border-color: rgba(255, 255, 255, 0.2);
            color: white;
        }

        .btn-secondary:hover {
            transform: scale(1.05);
        }

        .btn-secondary:active {
            transform: scale(0.95);
        }

        .hero-image {
            position: relative;
            display: flex;
            justify-content: center;
            max-width: 32rem;
            margin: 0 auto;
            width: 100%;
        }

        .hero-image-container {
            position: relative;
            aspect-ratio: 1;
            border-radius: 1.5rem;
            overflow: hidden;
            border: 1px solid rgba(255, 255, 255, 0.1);
            padding: 0.5rem;
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
            transform: rotate(3deg);
            transition: transform 0.5s ease;
            background: linear-gradient(to top right, rgba(34, 197, 94, 0.2), transparent);
        }

        .hero-image-container:hover {
            transform: rotate(0deg);
        }

        .hero-image img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            border-radius: 1rem;
        }

        #assets {
            padding: 6rem 1.5rem;
            position: relative;
            z-index: 10;
        }

        .section-container {
            max-width: 80rem;
            margin: 0 auto;
        }

        .section-header {
            text-align: center;
            margin-bottom: 4rem;
        }

        .section-header h2 {
            font-size: 2.25rem;
            font-weight: 700;
            margin-bottom: 1rem;
        }

        @media (min-width: 768px) {
            .section-header h2 {
                font-size: 3rem;
            }
        }

        .section-header p {
            color: #64748b;
            max-width: 40rem;
            margin: 0 auto;
            font-size: 1.125rem;
        }

        :root.dark .section-header p {
            color: #94a3b8;
        }

        .products-grid {
            display: grid;
            grid-template-columns: 1fr;
            gap: 2rem;
        }

        @media (min-width: 768px) {
            .products-grid {
                grid-template-columns: repeat(2, 1fr);
            }
        }

        @media (min-width: 1024px) {
            .products-grid {
                grid-template-columns: repeat(3, 1fr);
            }
        }

        .product-card {
            border-radius: 1.875rem;
            overflow: hidden;
            border: 1px solid rgba(255, 255, 255, 0.1);
            transition: all 0.3s ease;
            display: flex;
            flex-direction: column;
            background: var(--glass-bg);
            backdrop-filter: blur(12px);
        }

        .product-card:hover {
            transform: translateY(-0.5rem);
        }

        .product-image {
            position: relative;
            height: 16rem;
            overflow: hidden;
            padding: 0.5rem;
        }

        .product-image img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            border-radius: 1rem;
            transition: transform 0.5s ease;
        }

        .product-card:hover .product-image img {
            transform: scale(1.1);
        }

        .product-badge {
            position: absolute;
            top: 1rem;
            right: 1rem;
            background: rgba(0, 0, 0, 0.6);
            color: white;
            padding: 0.25rem 0.75rem;
            border-radius: 9999px;
            font-size: 0.75rem;
            font-weight: 600;
            border: 1px solid rgba(255, 255, 255, 0.1);
            z-index: 10;
        }

        [dir="rtl"] .product-badge {
            right: auto;
            left: 1rem;
        }

        .product-content {
            padding: 1.5rem;
            flex: 1;
            display: flex;
            flex-direction: column;
        }

        .product-title {
            font-size: 1.25rem;
            font-weight: 700;
            margin-bottom: 0.5rem;
        }

        .product-desc {
            font-size: 0.875rem;
            color: #64748b;
            margin-bottom: 1.5rem;
            flex: 1;
        }

        :root.dark .product-desc {
            color: #cbd5e1;
        }

        .product-footer {
            display: flex;
            justify-content: space-between;
            align-items: center;
            gap: 1rem;
        }

        .product-price {
            font-size: 1.875rem;
            font-weight: 900;
        }

        .btn-small {
            padding: 0.625rem 1.5rem;
            font-size: 0.875rem;
            background: rgba(0, 0, 0, 0.1);
            border: none;
            border-radius: 0.75rem;
            color: inherit;
            cursor: pointer;
            font-weight: 600;
            transition: all 0.3s ease;
            display: inline-flex;
            align-items: center;
            gap: 0.5rem;
            text-decoration: none;
        }

        :root.dark .btn-small {
            background: rgba(255, 255, 255, 0.1);
        }

        .btn-small:hover {
            background: var(--primary);
            color: white;
        }

        .proof-section {
            padding: 5rem 1.5rem;
            background: rgba(0, 0, 0, 0.05);
            border-top: 1px solid rgba(0, 0, 0, 0.05);
            border-bottom: 1px solid rgba(0, 0, 0, 0.05);
            position: relative;
            z-index: 10;
        }

        :root.dark .proof-section {
            background: rgba(0, 0, 0, 0.4);
            border-color: rgba(255, 255, 255, 0.05);
        }

        .proof-container {
            display: grid;
            grid-template-columns: 1fr;
            gap: 3rem;
            align-items: center;
            max-width: 80rem;
            margin: 0 auto;
        }

        @media (min-width: 768px) {
            .proof-container {
                grid-template-columns: 1fr 1fr;
            }
        }

        .proof-content {
            text-align: center;
        }

        @media (min-width: 768px) {
            .proof-content {
                text-align: left;
            }
        }

        .proof-content h2 {
            font-size: 1.875rem;
            font-weight: 700;
            margin-bottom: 1rem;
        }

        @media (min-width: 768px) {
            .proof-content h2 {
                font-size: 2.25rem;
            }
        }

        .proof-desc {
            color: #64748b;
            margin-bottom: 2rem;
            font-size: 1.125rem;
        }

        :root.dark .proof-desc {
            color: #94a3b8;
        }

        .stats {
            display: flex;
            gap: 1rem;
            flex-wrap: wrap;
            justify-content: center;
        }

        @media (min-width: 768px) {
            .stats {
                justify-content: flex-start;
            }
        }

        .stat {
            background: var(--glass-bg);
            backdrop-filter: blur(10px);
            padding: 1.5rem;
            border-radius: 1.25rem;
            display: flex;
            flex-direction: column;
        }

        .stat-number {
            font-size: 2.25rem;
            font-weight: 900;
            color: var(--foreground);
        }

        .stat-label {
            font-size: 0.75rem;
            color: var(--primary);
            font-weight: 500;
            text-transform: uppercase;
            letter-spacing: 0.1em;
            margin-top: 0.25rem;
        }

        .proof-videos {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: 1rem;
            max-width: 28rem;
            margin: 0 auto;
        }

        @media (min-width: 768px) {
            .proof-videos {
                margin: 0;
            }
        }

        .video-card {
            position: relative;
            aspect-ratio: 9 / 16;
            background: #e2e8f0;
            border-radius: 1rem;
            overflow: hidden;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.3s ease;
            border: 1px solid rgba(0, 0, 0, 0.05);
        }

        :root.dark .video-card {
            background: #1e293b;
            border-color: rgba(255, 255, 255, 0.1);
        }

        .video-card:nth-child(2) {
            transform: translateY(2rem);
        }

        .video-card:hover {
            background-color: rgba(0, 0, 0, 0);
        }

        .video-card img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            opacity: 0.6;
        }

        .play-button {
            position: absolute;
            width: 3rem;
            height: 3rem;
            background: rgba(255, 255, 255, 0.2);
            backdrop-filter: blur(4px);
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .play-icon {
            width: 1.5rem;
            height: 1.5rem;
            fill: white;
            margin-left: 0.25rem;
        }

        .video-label {
            position: absolute;
            bottom: 1rem;
            left: 1rem;
            color: white;
            z-index: 10;
        }

        .video-label p:first-child {
            font-weight: 700;
            font-size: 0.875rem;
        }

        .video-label p:last-child {
            font-size: 0.75rem;
            opacity: 0.8;
        }

        .newsletter-section {
            padding: 6rem 1.5rem;
            position: relative;
            z-index: 10;
        }

        .newsletter-card {
            max-width: 48rem;
            margin: 0 auto;
            padding: 2rem 2rem;
            border-radius: 2.5rem;
            text-align: center;
            border: 1px solid rgba(255, 255, 255, 0.2);
            border-top: 1px solid rgba(255, 255, 255, 0.2);
            border-left: 1px solid rgba(255, 255, 255, 0.2);
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
            position: relative;
            overflow: hidden;
            background: var(--glass-bg);
            backdrop-filter: blur(12px);
        }

        @media (min-width: 768px) {
            .newsletter-card {
                padding: 3rem;
            }
        }

        .newsletter-card::before {
            content: '';
            position: absolute;
            top: 0;
            right: 0;
            width: 16rem;
            height: 16rem;
            background: rgba(34, 197, 94, 0.2);
            filter: blur(80px);
            border-radius: 50%;
            pointer-events: none;
        }

        .newsletter-card h2 {
            font-size: 1.875rem;
            font-weight: 700;
            margin-bottom: 1rem;
            position: relative;
            z-index: 10;
        }

        @media (min-width: 768px) {
            .newsletter-card h2 {
                font-size: 3rem;
            }
        }

        .newsletter-desc {
            font-size: 1.125rem;
            color: #64748b;
            margin-bottom: 2rem;
            max-width: 28rem;
            margin-left: auto;
            margin-right: auto;
            position: relative;
            z-index: 10;
        }

        :root.dark .newsletter-desc {
            color: #cbd5e1;
        }

        .newsletter-form {
            display: flex;
            flex-direction: column;
            gap: 1rem;
            max-width: 28rem;
            margin: 0 auto;
            position: relative;
            z-index: 10;
        }

        @media (min-width: 640px) {
            .newsletter-form {
                flex-direction: row;
            }
        }

        .newsletter-input {
            flex: 1;
            background: rgba(0, 0, 0, 0.05);
            border: 1px solid rgba(0, 0, 0, 0.1);
            border-radius: 9999px;
            padding: 1rem 1.5rem;
            outline: none;
            font-size: 1rem;
            transition: border-color 0.3s ease;
            color: inherit;
        }

        :root.dark .newsletter-input {
            background: rgba(0, 0, 0, 0.4);
            border-color: rgba(255, 255, 255, 0.1);
            color: white;
        }

        .newsletter-input:focus {
            border-color: rgba(34, 197, 94, 0.5);
        }

        .newsletter-input::placeholder {
            color: #a0aec0;
        }

        .newsletter-button {
            background: #1f2937;
            color: white;
            padding: 1rem 2rem;
            border: none;
            border-radius: 9999px;
            font-weight: 700;
            cursor: pointer;
            transition: all 0.3s ease;
            white-space: nowrap;
            box-shadow: 0 0 15px rgba(255, 255, 255, 0.2);
        }

        .newsletter-button:hover {
            background: var(--primary);
            color: white;
            box-shadow: 0 0 20px rgba(34, 197, 94, 0.5);
        }

        .newsletter-button:active {
            transform: scale(0.95);
        }

        :root.dark .newsletter-button {
            background: white;
            color: black;
        }

        .newsletter-spam {
            font-size: 0.75rem;
            color: #94a3b8;
            margin-top: 1rem;
            position: relative;
            z-index: 10;
        }

        footer {
            border-top: 1px solid rgba(0, 0, 0, 0.05);
            background: rgba(0, 0, 0, 0.05);
            padding: 4rem 1.5rem 2rem;
            margin-top: auto;
            position: relative;
            z-index: 10;
            width: 100%;
        }

        :root.dark footer {
            background: rgba(0, 0, 0, 0.5);
            border-top-color: rgba(255, 255, 255, 0.1);
        }

        .footer-container {
            max-width: 80rem;
            margin: 0 auto;
            display: grid;
            grid-template-columns: 1fr;
            gap: 3rem;
            margin-bottom: 3rem;
        }

        @media (min-width: 768px) {
            .footer-container {
                grid-template-columns: 2fr 1fr 1fr;
            }
        }

        .footer-section h4 {
            font-weight: 700;
            margin-bottom: 1rem;
        }

        .footer-brand {
            font-size: 1.5rem;
            font-weight: 700;
            background: linear-gradient(to right, var(--primary), var(--accent));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
            display: inline-block;
            margin-bottom: 1rem;
        }

        .footer-desc {
            color: #64748b;
            max-width: 28rem;
            font-size: 0.875rem;
        }

        :root.dark .footer-desc {
            color: #94a3b8;
        }

        .footer-links {
            list-style: none;
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }

        .footer-links a {
            color: #64748b;
            text-decoration: none;
            font-size: 0.875rem;
            transition: color 0.3s ease;
        }

        .footer-links a:hover {
            color: var(--primary);
        }

        :root.dark .footer-links a {
            color: #94a3b8;
        }

        .footer-bottom {
            text-align: center;
            border-top: 1px solid rgba(0, 0, 0, 0.05);
            padding-top: 2rem;
            color: #64748b;
            font-size: 0.875rem;
        }

        :root.dark .footer-bottom {
            border-top-color: rgba(255, 255, 255, 0.05);
            color: #94a3b8;
        }

        .fab {
            position: fixed;
            bottom: 1.5rem;
            right: 1.5rem;
            z-index: 50;
            background: #22c55e;
            color: white;
            width: 3.5rem;
            height: 3.5rem;
            border-radius: 50%;
            border: none;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
            transition: all 0.3s ease;
        }

        [dir="rtl"] .fab {
            right: auto;
            left: 1.5rem;
        }

        .fab:hover {
            transform: scale(1.1);
            background: #16a34a;
        }

        .fab:active {
            transform: scale(0.9);
        }

        .notification {
            position: fixed;
            bottom: 1.5rem;
            left: 1.5rem;
            z-index: 50;
            background: var(--glass-bg);
            backdrop-filter: blur(12px);
            border: 1px solid rgba(34, 197, 94, 0.2);
            padding: 1rem;
            border-radius: 1.25rem;
            display: flex;
            gap: 1rem;
            align-items: center;
            box-shadow: 0 0 20px rgba(34, 197, 94, 0.1);
            animation: slideIn 0.3s ease;
            max-width: 20rem;
        }

        [dir="rtl"] .notification {
            right: 1.5rem;
            left: auto;
        }

        @keyframes slideIn {
            from {
                opacity: 0;
                transform: translateY(1.25rem) translateX(-1.25rem);
            }
            to {
                opacity: 1;
                transform: translateY(0) translateX(0);
            }
        }

        .notification-icon {
            background: rgba(34, 197, 94, 0.2);
            padding: 0.5rem;
            border-radius: 50%;
            flex-shrink: 0;
        }

        .notification-icon svg {
            width: 1.25rem;
            height: 1.25rem;
            color: var(--primary);
        }

        .notification-content p:first-child {
            font-size: 0.875rem;
            font-weight: 700;
            color: var(--foreground);
        }

        .notification-content p:last-child {
            font-size: 0.75rem;
            color: #64748b;
        }

        :root.dark .notification-content p:last-child {
            color: #cbd5e1;
        }

        .notification-close {
            background: none;
            border: none;
            cursor: pointer;
            color: #64748b;
            padding: 0;
            margin-left: auto;
            flex-shrink: 0;
        }

        .modal {
            display: none;
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.5);
            backdrop-filter: blur(4px);
            z-index: 100;
            align-items: center;
            justify-content: center;
            padding: 1.5rem;
        }

        .modal.active {
            display: flex;
            animation: fadeIn 0.3s ease;
        }

        @keyframes fadeIn {
            from {
                opacity: 0;
            }
            to {
                opacity: 1;
            }
        }

        .modal-content {
            background: var(--background);
            border-radius: 1.5rem;
            max-width: 48rem;
            max-height: 80vh;
            overflow-y: auto;
            padding: 2rem;
            position: relative;
            animation: slideUp 0.3s ease;
        }

        @keyframes slideUp {
            from {
                transform: translateY(2rem);
                opacity: 0;
            }
            to {
                transform: translateY(0);
                opacity: 1;
            }
        }

        .modal-close {
            position: absolute;
            top: 1.5rem;
            right: 1.5rem;
            background: none;
            border: none;
            font-size: 1.5rem;
            cursor: pointer;
            color: inherit;
        }

        [dir="rtl"] .modal-close {
            right: auto;
            left: 1.5rem;
        }

        .modal h2 {
            font-size: 2rem;
            font-weight: 700;
            margin-bottom: 1.5rem;
            margin-top: 0;
        }

        .modal h3 {
            font-size: 1.25rem;
            font-weight: 700;
            margin: 1.5rem 0 0.75rem 0;
        }

        .modal p {
            color: #64748b;
            line-height: 1.75;
            margin-bottom: 1rem;
        }

        :root.dark .modal p {
            color: #cbd5e1;
        }

        .modal ul {
            list-style: none;
            padding-left: 0;
        }

        .modal ul li {
            color: #64748b;
            margin-bottom: 0.5rem;
            padding-left: 1.5rem;
            position: relative;
        }

        :root.dark .modal ul li {
            color: #cbd5e1;
        }

        .modal ul li::before {
            content: '✓';
            position: absolute;
            left: 0;
            color: var(--primary);
            font-weight: 700;
        }

        .text-gradient {
            background: linear-gradient(to right, var(--primary), var(--accent));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        .mobile-menu-toggle {
            display: none;
            background: none;
            border: none;
            cursor: pointer;
            color: inherit;
            font-size: 1.5rem;
        }

        @media (max-width: 1023px) {
            .mobile-menu-toggle {
                display: block;
            }
        }

        html {
            scroll-behavior: smooth;
        }

head.script:
//
        const translations = {
