                    desc: 'Drop your email to get free digital wallpapers, early access to new POD assets, and a weekly dose of animal-tech madness.',
                    placeholder: 'Enter your email...',
                    btn: 'Subscribe Now',
                    spam: 'No spam. Just quality content. Unsubscribe anytime.'
                },
                footer: {
                    desc: 'The premier destination for viral animal-tech digital assets. Quality tools for quality creators.',
                    quickLinks: 'Quick Links',
                    legal: 'Legal',
                    terms: 'Terms of Service',
                    privacy: 'Privacy Policy',
                    license: 'Licensing Info',
                    copyright: '© 2026 Mohameden 351. All rights reserved.'
                },
            },
            ar: {
                nav: {
                    home: 'الرئيسية',
                    assets: 'الأصول الرقمية',
                    pod: 'تصاميم الطباعة',
                    guides: 'أدلة تيك توك',
                    creator: 'صانع المحتوى',
                    contact: 'تواصل معنا',
                    shop: 'تسوق الآن',
                },
                hero: {
                    badge: '🐐 أصول تيك توك الفيروسية متاحة الآن',
                    title1: 'ارتقِ بمحتواك الرقمي مع',
                    title2: 'أصول الماعز الفيروسية',
                    desc: 'فن رقمي حصري، قوالب طباعة عند الطلب عالية التحويل، وأصول مميزة مصممة للمبدعين الذين يرغبون في التميز. احصل على نفس الموارد المستخدمة في أشهر مقاطع تيك توك.',
                    btn1: 'تصفح الأصول',
                    btn2: 'شاهد تيك توك',
                },
                products: {
                    title: 'أصول رقمية مميزة',
                    desc: 'افتح الملفات الدقيقة المستخدمة لإنشاء روائع حصدت ملايين المشاهدات. تسليم فوري، حقوق تجارية كاملة.',
                    badges: ['الأكثر مبيعاً', '', 'عروض الحزم'],
                    titles: ['قط البودكاست الرائع – 4K/HD', 'أفضل لقطات الماعز', 'فن القطة اللطيفة وأصدقائها'],
                    descs: ['فن رقمي عالي الدقة وفائق التفاصيل، مثالي لعشاق التكنولوجيا وصناع المحتوى. يتضمن الملفات الأصلية.', 'مقاطع 4K أصلية – مثالية للوثائقيات والميمز. تحميل فوري على Gumroad.', 'فن رقمي ثلاثي الأبعاد حصري ورائع يضم قطة لطيفة وماعز. مثالي لمحبي الحيوانات.'],
                    prices: ['$2', '$10', 'خاص'],
                    btn: 'اشتري الآن 🛒'
                },
                proof: {
                    title: 'موثوق من قبل أكثر من 500 ألف متابع',
                    desc: 'انضم إلى المجتمع واكتشف لماذا تولّد أصول @mohameden351 باستمرار لحظات فيروسية عبر تيك توك.',
                    stats: ['مشاهدة', 'تحميل', 'تقييم'],
                    videoDesc1: 'تعديل الماعز الفيروسي 🐐🔥',
                    videoDesc2: 'عملية القط التكنولوجي 💻'
                },
                newsletter: {
                    title: 'فكاهة وتصاميم الماعز الأسبوعية',
                    desc: 'أدخل بريدك الإلكتروني للحصول على خلفيات رقمية مجانية، ووصول مبكر لأصول الطباعة الجديدة، وجرعة أسبوعية من جنون التكنولوجيا والحيوانات.',
                    placeholder: 'أدخل بريدك الإلكتروني...',
                    btn: 'اشترك الآن',
                    spam: 'لا رسائل مزعجة. محتوى عالي الجودة فقط. إلغاء الاشتراك في أي وقت.'
                },
                footer: {
                    desc: 'الوجهة الأولى لأصول التكنولوجيا والحيوانات الرقمية الفيروسية. أدوات جودة للمبدعين المميزين.',
                    quickLinks: 'روابط سريعة',
                    legal: 'قانوني',
                    terms: 'شروط الخدمة',
                    privacy: 'سياسة الخصوصية',
                    license: 'معلومات الترخيص',
                    copyright: '© 2026 Mohameden 351. جميع الحقوق محفوظة.'
                },
            }
        };

        let isDark = localStorage.getItem('isDark') === null ? true : localStorage.getItem('isDark') === 'true';
        let lang = localStorage.getItem('lang') || 'en';
        let currency = localStorage.getItem('currency') || 'USD';

        // Page navigation functions - defined globally
        const pages = {
            home: () => showSections(['#home', '#assets', '.proof-section', '.newsletter-section']),
            assets: () => showPage('digitalAssetsPage'),
            creator: () => showPage('creatorPage'),
            contact: () => showPage('contactPage'),
            pod: () => showPage('podAssetsPage'),
            guides: () => showPage('tiktokGuidesPage'),
        };

        function showPage(pageId) {
            document.querySelectorAll('[id$="Page"], #home, #assets, .proof-section, .newsletter-section').forEach(el => {
                el.style.display = 'none';
            });
            const page = document.getElementById(pageId);
            if (page) page.style.display = 'block';
            window.scrollTo(0, 80);
        }

        function showSections(selectors) {
            document.querySelectorAll('[id$="Page"]').forEach(el => {
                el.style.display = 'none';
            });
            document.querySelectorAll('#home, #assets, .proof-section, .newsletter-section').forEach(el => {
                el.style.display = 'block';
            });
            window.scrollTo(0, 0);
        }

        function initTheme() {
            if (isDark) {
                document.documentElement.classList.add('dark');
                document.getElementById('themeToggle').textContent = '🌙';
            } else {
                document.documentElement.classList.remove('dark');
                document.getElementById('themeToggle').textContent = '☀️';
            }
        }

        function applyTranslations() {
            const t = translations[lang];
            if (!t) return;
            
            const navLinks = document.querySelectorAll('.nav-links a');
            if (navLinks.length >= 6) {
                navLinks[0].textContent = t.nav.home;
                navLinks[1].textContent = t.nav.assets;
                navLinks[2].textContent = t.nav.pod;
                navLinks[3].textContent = t.nav.guides;
                navLinks[4].textContent = t.nav.creator;
                navLinks[5].textContent = t.nav.contact;
            }
            const shopBtn = document.querySelector('.nav-shop');
            if(shopBtn) shopBtn.textContent = t.nav.shop;

            const badge = document.querySelector('.hero-badge');
            if(badge) badge.textContent = t.hero.badge;
            const heroTitle = document.querySelector('.hero-title');
            if(heroTitle) heroTitle.innerHTML = t.hero.title1 + ' <span>' + t.hero.title2 + '</span>';
            const heroDesc = document.querySelector('.hero-desc');
            if(heroDesc) heroDesc.textContent = t.hero.desc;
            const heroBtn1 = document.querySelector('.hero-buttons .btn-primary');
            if(heroBtn1) {
                // Keep the arrow if it was there or just text
                heroBtn1.textContent = t.hero.btn1 + (lang === 'en' ? ' →' : ' ←');
            }
            const heroBtn2 = document.querySelector('.hero-buttons .btn-secondary');
            if(heroBtn2) heroBtn2.textContent = t.hero.btn2;

            const prodHeader = document.querySelector('#assets .section-header h2');
            if(prodHeader) prodHeader.textContent = t.products.title;
            const prodDesc = document.querySelector('#assets .section-header p');
            if(prodDesc) prodDesc.textContent = t.products.desc;

            const productCards = document.querySelectorAll('#assets .product-card');
            productCards.forEach((card, index) => {
                if(t.products.titles && t.products.titles[index]) {
                    const badge = card.querySelector('.product-badge');
                    if(badge && t.products.badges[index]) badge.textContent = t.products.badges[index];
                    
                    const title = card.querySelector('.product-title');
                    if(title) title.textContent = t.products.titles[index];
                    
                    const desc = card.querySelector('.product-desc');
                    if(desc) desc.textContent = t.products.descs[index];
                    
                    const price = card.querySelector('.product-price');
                    if(price) price.textContent = t.products.prices[index];
                    
                    const btn = card.querySelector('.btn-small');
                    if(btn) btn.textContent = t.products.btn;
                }
            });

            const proofHeader = document.querySelector('.proof-content h2');
            if(proofHeader) proofHeader.textContent = t.proof.title;
            const proofDesc = document.querySelector('.proof-desc');
            if(proofDesc) proofDesc.textContent = t.proof.desc;

            const statsLabels = document.querySelectorAll('.stat-label');
            statsLabels.forEach((label, index) => {
                if(t.proof.stats && t.proof.stats[index]) label.textContent = t.proof.stats[index];
            });
            const videos = document.querySelectorAll('.video-label p:last-child');
            if(videos.length >= 2 && t.proof.videoDesc1) {
                videos[0].textContent = t.proof.videoDesc1;
                videos[1].textContent = t.proof.videoDesc2;
            }

            const newsHeader = document.querySelector('.newsletter-card h2');
            if(newsHeader) newsHeader.textContent = t.newsletter.title;
            const newsDesc = document.querySelector('.newsletter-desc');
            if(newsDesc) newsDesc.textContent = t.newsletter.desc;
            const newsInput = document.querySelector('.newsletter-input');
            if(newsInput && t.newsletter.placeholder) newsInput.placeholder = t.newsletter.placeholder;
            const newsBtn = document.querySelector('.newsletter-button');
            if(newsBtn && t.newsletter.btn) newsBtn.textContent = t.newsletter.btn;
            const newsSpam = document.querySelector('.newsletter-spam');
            if(newsSpam && t.newsletter.spam) newsSpam.textContent = t.newsletter.spam;

            const footDesc = document.querySelector('.footer-desc');
            if(footDesc) footDesc.textContent = t.footer.desc;
            const footHeaders = document.querySelectorAll('.footer-section h4');
            if(footHeaders.length >= 2 && t.footer.quickLinks) {
                footHeaders[0].textContent = t.footer.quickLinks;
                footHeaders[1].textContent = t.footer.legal;
            }
            
            const footLinks = document.querySelectorAll('.footer-section:nth-child(2) .footer-links a');
            if(footLinks.length >= 5) {
                footLinks[0].textContent = t.nav.assets;
                footLinks[1].textContent = t.nav.pod;
                footLinks[2].textContent = t.nav.guides;
                footLinks[3].textContent = t.nav.creator;
                footLinks[4].textContent = t.nav.contact;
            }

            const legalLinks = document.querySelectorAll('.footer-section:nth-child(3) .footer-links a');
            if(legalLinks.length >= 3 && t.footer.terms) {
                legalLinks[0].textContent = t.footer.terms;
                legalLinks[1].textContent = t.footer.privacy;
                legalLinks[2].textContent = t.footer.license;
            }

            const footBottom = document.querySelector('.footer-bottom');
            if(footBottom && t.footer.copyright) footBottom.textContent = t.footer.copyright;
        }

        function initLanguage() {
            document.documentElement.lang = lang;
            document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
            document.getElementById('langToggle').textContent = lang.toUpperCase() === 'AR' ? 'AR عربي' : '🌐 EN';
            applyTranslations();
        }

        function initCurrency() {
            document.getElementById('currencyToggle').textContent = currency === 'USD' ? '💵 USD' : '💵 MAD';
        }

        function toggleTheme() {
            isDark = !isDark;
            localStorage.setItem('isDark', isDark);
            initTheme();
        }

        function toggleLanguage() {
            lang = lang === 'en' ? 'ar' : 'en';
            localStorage.setItem('lang', lang);
            initLanguage();
        }

        function toggleCurrency() {
            currency = currency === 'USD' ? 'Local' : 'USD';
            localStorage.setItem('currency', currency);
            initCurrency();
        }

        function handleScroll() {
            const navbar = document.getElementById('navbar');
            if (window.scrollY > 20) {
                navbar.classList.add('scrolled');
            } else {
                navbar.classList.remove('scrolled');
            }
        }

        function handleNewsletterSubmit(e) {
            e.preventDefault();
            alert(lang === 'ar' ? 'شكراً على اشتراكك!' : 'Thank you for subscribing!');
            e.target.reset();
        }

        function openModal(elem, evt) {
            if (evt) evt.preventDefault();
            const modalType = elem.getAttribute('data-modal');
            const modal = document.getElementById(modalType + 'Modal');
            if (modal) {
                modal.classList.add('active');
                document.body.style.overflow = 'hidden';
            }
        }

        function closeModal(elem) {
            const modal = elem.closest('.modal');
            if (modal) {
                modal.classList.remove('active');
                document.body.style.overflow = 'auto';
            }
        }

        function closeNotification() {
            document.getElementById('notification').style.display = 'none';
        }

        function showNotification() {
            const notification = document.getElementById('notification');
            const messages = {
                en: [
                    { title: 'Someone from USA', message: 'Just purchased Goat Assets' },
                    { title: 'Someone from Saudi Arabia', message: 'Just purchased POD Template' },
                    { title: 'Someone from Egypt', message: 'Just purchased Digital Art Pack' }
                ],
                ar: [
                    { title: 'شخص من المملكة العربية السعودية', message: 'اشترى للتو أصول الماعز' },
                    { title: 'شخص من مصر', message: 'اشترى للتو قالب الطباعة' },
                    { title: 'شخص من الإمارات', message: 'اشترى للتو حزمة الفن الرقمي' }
                ]
            };

            const msg = messages[lang][Math.floor(Math.random() * messages[lang].length)];
            document.getElementById('notification-title').textContent = msg.title;
            document.getElementById('notification-message').textContent = msg.message;
            notification.style.display = 'flex';

            setTimeout(() => {
                notification.style.display = 'none';
            }, 5000);
        }

        document.addEventListener('DOMContentLoaded', function() {
            document.getElementById('themeToggle').addEventListener('click', toggleTheme);
            document.getElementById('langToggle').addEventListener('click', toggleLanguage);
            document.getElementById('currencyToggle').addEventListener('click', toggleCurrency);
            window.addEventListener('scroll', handleScroll);

            // Attach navigation to buttons
            document.querySelectorAll('nav a').forEach(link => {
                link.addEventListener('click', (e) => {
                    const href = link.getAttribute('href');
                    if (href.startsWith('#')) {
                        e.preventDefault();
                        const page = href.substring(1);
                        if (pages[page]) pages[page]();
                    }
                });
            });

            // Handle hash routing
            window.addEventListener('hashchange', () => {
                const page = window.location.hash.substring(1);
                if (pages[page]) pages[page]();
            });

            document.querySelectorAll('.modal').forEach(modal => {
                modal.addEventListener('click', (e) => {
                    if (e.target === modal) {
                        closeModal(modal.querySelector('.modal-close'));
                    }
                });
            });

            setInterval(showNotification, 15000);

            initTheme();
            initLanguage();
            initCurrency();
        });
    //
